/* @module 0xda47f508f5b48c56d84e14e3c97bac8f */
export default { name: 'tagall', alias: ['everyone', 'listall', 'members', 'taglist'], category: 'group', description: 'List and tag all members in the group', async execute(sock, msg, args, PREFIX, extra) { const chatId = msg.key.remoteJid; const isGroup = chatId.endsWith('@g.us'); if (!isGroup) { return sock.sendMessage(chatId, { text: `тФМтФАтзн *GROUP ONLY* ЁЯСе тзнтФАтФР тФВ тФЬтФАтзн This command only works in groups! тФВ тФФтФАтзнЁЯжК` }, { quoted: msg }); } try { const groupMetadata = await sock.groupMetadata(chatId); const participants = groupMetadata.participants; const senderId = msg.key.participant || chatId; const isSenderAdmin = participants.find(p => p.id === senderId)?.admin === 'admin' || participants.find(p => p.id === senderId)?.admin === 'superadmin'; if (!isSenderAdmin && !msg.key.fromMe) { return sock.sendMessage(chatId, { text: `тФМтФАтзн *ADMIN ONLY* ЁЯСС тзнтФАтФР тФВ тФЬтФАтзн Only admins can tag everyone! тФВ тФФтФАтзнЁЯжК` }, { quoted: msg }); } const message = args.join(' ').trim() || 'ЁЯУв Group Members List'; const admins = participants.filter(p => p.admin === 'admin' || p.admin === 'superadmin'); const members = participants.filter(p => !p.admin); const sortByName = (a, b) => { const nameA = a.name || a.id.split('@')[0]; const nameB = b.name || b.id.split('@')[0]; return nameA.localeCompare(nameB); }; admins.sort(sortByName); members.sort(sortByName); let listText = `тФМтФАтзн *${message}* ЁЯСе тзнтФАтФР тФВ тФЬтФАтзн *Group:* ${groupMetadata.subject} тФЬтФАтзн *Total Members:* ${participants.length} тФЬтФАтзн *Admins:* ${admins.length} тФЬтФАтзн *Members:* ${members.length} тФВ тФЬтФАтзн *ЁЯСС ADMIN LIST*\n`; if (admins.length > 0) { admins.forEach((admin, index) => { const isSuper = admin.admin === 'superadmin' ? 'ЁЯСС' : 'ЁЯФ░'; const name = admin.name || admin.id.split('@')[0]; const number = admin.id.split('@')[0]; listText += `тФВ ${index + 1}. ${isSuper} @${number} ${name !== number ? `(${name})` : ''}\n`; }); } else { listText += `тФВ No admins found\n`; } listText += `тФВ тФЬтФАтзн *ЁЯСе MEMBER LIST*\n`; if (members.length > 0) { for (let i = 0; i < members.length; i++) { const member = members[i]; const name = member.name || member.id.split('@')[0]; const number = member.id.split('@')[0]; listText += `тФВ ${i + 1}. ЁЯСд @${number} ${name !== number ? `(${name})` : ''}\n`; if ((i + 1) % 50 === 0 && i < members.length - 1) { listText += `тФВ\nтФФтФАтзнЁЯжК *Continued...*`; const chunkMentions = members.slice(i - 49, i + 1).map(m => m.id); await sock.sendMessage(chatId, { text: listText, mentions: [...admins.map(a => a.id), ...chunkMentions] }, { quoted: msg }); listText = `тФМтФАтзн *${message} (Continued)* ЁЯСе тзнтФАтФР\nтФВ\n`; } } } else { listText += `тФВ No members found\n`; } listText += `тФВ тФЬтФАтзн *Total:* ${participants.length} members тФЬтФАтзн *Requested by:* ${msg.pushName || 'Admin'} тФВ тФФтФАтзнЁЯжК`; const allMentions = participants.map(p => p.id); await sock.sendMessage(chatId, { text: listText, mentions: allMentions }, { quoted: msg }); console.log(`ЁЯУЛ Tagall list sent in ${groupMetadata.subject} with ${participants.length} members`); } catch (error) { console.error('Tagall error:', error); await sock.sendMessage(chatId, { text: `тФМтФАтзн *ERROR* тЭМ тзнтФАтФР тФВ тФЬтФАтзн ${error.message} тФВ тФЬтФАтзн *Possible reasons:* тФВ тАв Too many members тФВ тАв Network issue тФВ тАв Bot not admin тФВ тФФтФАтзнЁЯжК` }, { quoted: msg }); } } };